mapper.select:
SELECT
    id, role_code, role_name, menu_perms, data_scope, status, remark, create_time, update_time
FROM sys_role


        AND id = #{id}


        AND role_code = #{roleCode}


        AND role_name LIKE CONCAT('%', #{roleName}, '%')


        AND status = #{status}


ORDER BY create_time DESC

mapper.update:
UPDATE sys_role
role_code = #{roleCode}, role_name = #{roleName}, menu_perms = #{menuPerms}, data_scope = #{dataScope}, status = #{status}, remark = #{remark}, update_time = #{updateTime}
WHERE id = #{id}
